SELECT 'workspaces' t, count(*) FROM workspaces UNION ALL SELECT 'tenants', count(*) FROM information_schema.tables WHERE table_name='tenants' AND table_schema='public' UNION ALL SELECT 'rfi_responses', count(*) FROM rfi_responses UNION ALL SELECT 'daily_weather', count(*) FROM daily_weather UNION ALL SELECT 'auth_users', count(*) FROM auth.users UNION ALL SELECT 'projects', count(*) FROM projects;